		$template_file = is_file("./{$templateDVP}") ? "./{$templateDVP}" : './templates/goal_setting_table_templateDVP.html';
		$templateCode = @file_get_contents($template_file);
	} else {
		$template_file = is_file("./{$templateDV}") ? "./{$templateDV}" : './templates/goal_setting_table_templateDV.html';
		$templateCode = @file_get_contents($template_file);
	}

	// process form title
	$templateCode = str_replace('<%%DETAIL_VIEW_TITLE%%>', 'Goal setting table details', $templateCode);
	$templateCode = str_replace('<%%RND1%%>', $rnd1, $templateCode);
	$templateCode = str_replace('<%%EMBEDDED%%>', (Request::val('Embedded') ? 'Embedded=1' : ''), $templateCode);
	// process buttons
	if($showSaveNew) {
		$templateCode = str_replace('<%%INSERT_BUTTON%%>', '<button type="submit" class="btn btn-success" id="insert" name="insert_x" value="1"><i class="glyphicon glyphicon-plus-sign"></i> ' . $Translation['Save New'] . '</button>', $templateCode);
	} elseif($showSaveAsCopy) {
		$templateCode = str_replace('<%%INSERT_BUTTON%%>', '<button type="submit" class="btn btn-default" id="insert" name="insert_x" value="1"><i class="glyphicon glyphicon-plus-sign"></i> ' . $Translation['Save As Copy'] . '</button>', $templateCode);
	} else {
		$templateCode = str_replace('<%%INSERT_BUTTON%%>', '', $templateCode);
	}

	// 'Back' button action
	if(Request::val('Embedded')) {
		$backAction = 'AppGini.closeParentModal(); return false;';
	} else {
		$backAction = 'return true;';
	}

	if($hasSelectedId) {
		if(!Request::val('Embedded')) $templateCode = str_replace('<%%DVPRINT_BUTTON%%>', '<button type="submit" class="btn btn-default" id="dvprint" name="dvprint_x" value="1" title="' . html_attr($Translation['Print Preview']) . '"><i class="glyphicon glyphicon-print"></i> ' . $Translation['Print Preview'] . '</button>', $templateCode);
		if($allowUpdate)
			$templateCode = str_replace('<%%UPDATE_BUTTON%%>', '<button type="submit" class="btn btn-success btn-lg" id="update" name="update_x" value="1" title="' . html_attr($Translation['Save Changes']) . '"><i class="glyphicon glyphicon-ok"></i> ' . $Translation['Save Changes'] . '</button>', $templateCode);
		else
			$templateCode = str_replace('<%%UPDATE_BUTTON%%>', '', $templateCode);

		if($allowDelete)
			$templateCode = str_replace('<%%DELETE_BUTTON%%>', '<button type="submit" class="btn btn-danger" id="delete" name="delete_x" value="1" title="' . html_attr($Translation['Delete']) . '"><i class="glyphicon glyphicon-trash"></i> ' . $Translation['Delete'] . '</button>', $templateCode);
		else
			$templateCode = str_replace('<%%DELETE_BUTTON%%>', '', $templateCode);

		$templateCode = str_replace('<%%DESELECT_BUTTON%%>', '<button type="submit" class="btn btn-default ltr" id="deselect" name="deselect_x" value="1" onclick="' . $backAction . '" title="' . html_attr($Translation['Back']) . '"><i class="glyphicon glyphicon-chevron-left"></i> ' . $Translation['Back'] . '</button>', $templateCode);
	} else {
		$templateCode = str_replace('<%%UPDATE_BUTTON%%>', '', $templateCode);
		$templateCode = str_replace('<%%DELETE_BUTTON%%>', '', $templateCode);

		// if not in embedded mode and user has insert only but no view/update/delete,
		// remove 'back' button
		if(
			$allowInsert
			&& !$allowUpdate && !$allowDelete && !$arrPerm['view']
			&& !Request::val('Embedded')
		)
			$templateCode = str_replace('<%%DESELECT_BUTTON%%>', '', $templateCode);
		elseif($separateDV)
			$templateCode = str_replace(
				'<%%DESELECT_BUTTON%%>',
				'<button
					type="submit"
					class="btn btn-default ltr"
					id="deselect"
					name="deselect_x"
					value="1"
					onclick="' . $backAction . '"
					title="' . html_attr($Translation['Back']) . '">
						<i class="glyphicon glyphicon-chevron-left"></i> ' .
						$Translation['Back'] .
				'</button>',
				$templateCode
			);
		else
			$templateCode = str_replace('<%%DESELECT_BUTTON%%>', '', $templateCode);
	}

	// set records to read only if user can't insert new records and can't edit current record
	if(!$fieldsAreEditable) {
		$jsReadOnly = '';
		$jsReadOnly .= "\t\$j('#goal_status').replaceWith('<div class=\"form-control-static\" id=\"goal_status\">' + (\$j('#goal_status').val() || '') + '</div>'); \$j('#goal_status-multi-selection-help').hide();\n";
		$jsReadOnly .= "\t\$j('#goal_description').replaceWith('<div class=\"form-control-static\" id=\"goal_description\">' + (\$j('#goal_description').val() || '') + '</div>');\n";
		$jsReadOnly .= "\t\$j('#goal_duration').replaceWith('<div class=\"form-control-static\" id=\"goal_duration\">' + (\$j('#goal_duration').val() || '') + '</div>'); \$j('#goal_duration-multi-selection-help').hide();\n";
		$jsReadOnly .= "\t\$j('#goal_set_date').prop('readonly', true);\n";
		$jsReadOnly .= "\t\$j('#goal_set_dateDay, #goal_set_dateMonth, #goal_set_dateYear').prop('disabled', true).css({ color: '#555', backgroundColor: '#fff' });\n";
		$jsReadOnly .= "\t\$j('#supervisor_name').prop('disabled', true).css({ color: '#555', backgroundColor: '#fff' });\n";
		$jsReadOnly .= "\t\$j('#supervisor_name_caption').prop('disabled', true).css({ color: '#555', backgroundColor: 'white' });\n";
		$jsReadOnly .= "\t\$j('#assigned_to').prop('disabled', true).css({ color: '#555', backgroundColor: '#fff' });\n";
		$jsReadOnly .= "\t\$j('#assigned_to_caption').prop('disabled', true).css({ color: '#555', backgroundColor: 'white' });\n";
		$jsReadOnly .= "\t\$j('.select2-container').hide();\n";

		$noUploads = true;
	} else {
		// temporarily disable form change handler till time and datetime pickers are enabled
		$jsEditable = "\t\$j('form').eq(0).data('already_changed', true);";
		$jsEditable .= "\t\$j('form').eq(0).data('already_changed', false);"; // re-enable form change handler
	}

	// process combos
	$templateCode = str_replace('<%%COMBO(goal_status)%%>', $combo_goal_status->HTML, $templateCode);
	$templateCode = str_replace('<%%COMBOTEXT(goal_status)%%>', $combo_goal_status->SelectedData, $templateCode);
	$templateCode = str_replace('<%%COMBO(goal_duration)%%>', $combo_goal_duration->HTML, $templateCode);
	$templateCode = str_replace('<%%COMBOTEXT(goal_duration)%%>', $combo_goal_duration->SelectedData, $templateCode);
	$templateCode = str_replace(
		'<%%COMBO(goal_set_date)%%>',
		(!$fieldsAreEditable ?
			'<div class="form-control-static">' . $combo_goal_set_date->GetHTML(true) . '</div>' :
			$combo_goal_set_date->GetHTML()
		), $templateCode);
	$templateCode = str_replace('<%%COMBOTEXT(goal_set_date)%%>', $combo_goal_set_date->GetHTML(true), $templateCode);
	$templateCode = str_replace('<%%COMBO(supervisor_name)%%>', $combo_supervisor_name->HTML, $templateCode);
	$templateCode = str_replace('<%%COMBOTEXT(supervisor_name)%%>', $combo_supervisor_name->MatchText, $templateCode);
	$templateCode = str_replace('<%%URLCOMBOTEXT(supervisor_name)%%>', urlencode($combo_supervisor_name->MatchText), $templateCode);
	$templateCode = str_replace('<%%COMBO(assigned_to)%%>', $combo_assigned_to->HTML, $templateCode);
	$templateCode = str_replace('<%%COMBOTEXT(assigned_to)%%>', $combo_assigned_to->MatchText, $templateCode);
	$templateCode = str_replace('<%%URLCOMBOTEXT(assigned_to)%%>', urlencode($combo_assigned_to->MatchText), $templateCode);

	/* lookup fields array: 'lookup field name' => ['parent table name', 'lookup field caption'] */
	$lookup_fields = ['supervisor_name' => ['user_table', 'Supervisor name'], 'assigned_to' => ['user_table', 'Assigned to'], ];
	foreach($lookup_fields as $luf => $ptfc) {
		$pt_perm = getTablePermissions($ptfc[0]);

		// process foreign key links
		if(($pt_perm['view'] && isDetailViewEnabled($ptfc[0])) || $pt_perm['edit']) {
			$templateCode = str_replace("<%%PLINK({$luf})%%>", '<button type="button" class="btn btn-default view_parent" id="' . $ptfc[0] . '_view_parent" title="' . html_attr($Translation['View'] . ' ' . $ptfc[1]) . '"><i class="glyphicon glyphicon-eye-open"></i></button>', $templateCode);
		}

		// if user has insert permission to parent table of a lookup field, put an add new button
		if($pt_perm['insert'] /* && !Request::val('Embedded')*/) {
			$templateCode = str_replace("<%%ADDNEW({$ptfc[0]})%%>", '<button type="button" class="btn btn-default add_new_parent" id="' . $ptfc[0] . '_add_new" title="' . html_attr($Translation['Add New'] . ' ' . $ptfc[1]) . '"><i class="glyphicon glyphicon-plus text-success"></i></button>', $templateCode);
		}
	}

	// process images
	$templateCode = str_replace('<%%UPLOADFILE(goal_id)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(goal_status)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(goal_description)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(goal_duration)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(goal_set_date)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(supervisor_name)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(assigned_to)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(goal_setting_str)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(created_by)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(last_updated_by)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(created_by_username)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(created_at)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(last_updated_by_username)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(last_updated_at)%%>', '', $templateCode);

	// process values
	if($hasSelectedId) {
		$templateCode = str_replace('<%%VALUE(goal_id)%%>', safe_html($urow['goal_id']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(goal_id)%%>', urlencode($urow['goal_id']), $templateCode);
		if( $dvprint) $templateCode = str_replace('<%%VALUE(goal_status)%%>', safe_html($urow['goal_status']), $templateCode);
		if(!$dvprint) $templateCode = str_replace('<%%VALUE(goal_status)%%>', html_attr($row['goal_status']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(goal_status)%%>', urlencode($urow['goal_status']), $templateCode);
		$templateCode = str_replace('<%%VALUE(goal_description)%%>', safe_html($urow['goal_description'], $fieldsAreEditable), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(goal_description)%%>', urlencode($urow['goal_description']), $templateCode);
		if( $dvprint) $templateCode = str_replace('<%%VALUE(goal_duration)%%>', safe_html($urow['goal_duration']), $templateCode);
		if(!$dvprint) $templateCode = str_replace('<%%VALUE(goal_duration)%%>', html_attr($row['goal_duration']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(goal_duration)%%>', urlencode($urow['goal_duration']), $templateCode);
		$templateCode = str_replace('<%%VALUE(goal_set_date)%%>', app_datetime($row['goal_set_date']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(goal_set_date)%%>', urlencode(app_datetime($urow['goal_set_date'])), $templateCode);
		if( $dvprint) $templateCode = str_replace('<%%VALUE(supervisor_name)%%>', safe_html($urow['supervisor_name']), $templateCode);
		if(!$dvprint) $templateCode = str_replace('<%%VALUE(supervisor_name)%%>', html_attr($row['supervisor_name']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(supervisor_name)%%>', urlencode($urow['supervisor_name']), $templateCode);
		if( $dvprint) $templateCode = str_replace('<%%VALUE(assigned_to)%%>', safe_html($urow['assigned_to']), $templateCode);
		if(!$dvprint) $templateCode = str_replace('<%%VALUE(assigned_to)%%>', html_attr($row['assigned_to']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(assigned_to)%%>', urlencode($urow['assigned_to']), $templateCode);
		$templateCode = str_replace('<%%VALUE(goal_setting_str)%%>', safe_html($urow['goal_setting_str'], $fieldsAreEditable), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(goal_setting_str)%%>', urlencode($urow['goal_setting_str']), $templateCode);
		$templateCode = str_replace('<%%VALUE(created_by)%%>', safe_html($urow['created_by']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(created_by)%%>', urlencode($urow['created_by']), $templateCode);
		$templateCode = str_replace('<%%VALUE(last_updated_by)%%>', safe_html($urow['last_updated_by']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(last_updated_by)%%>', urlencode($urow['last_updated_by']), $templateCode);
		$templateCode = str_replace('<%%VALUE(created_by_username)%%>', safe_html($urow['created_by_username']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(created_by_username)%%>', urlencode($urow['created_by_username']), $templateCode);
		$templateCode = str_replace('<%%VALUE(created_at)%%>', safe_html($urow['created_at']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(created_at)%%>', urlencode($urow['created_at']), $templateCode);
		$templateCode = str_replace('<%%VALUE(last_updated_by_username)%%>', safe_html($urow['last_updated_by_username']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(last_updated_by_username)%%>', urlencode($urow['last_updated_by_username']), $templateCode);
		$templateCode = str_replace('<%%VALUE(last_updated_at)%%>', safe_html($urow['last_updated_at']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(last_updated_at)%%>', urlencode($urow['last_updated_at']), $templateCode);
	} else {
		$templateCode = str_replace('<%%VALUE(goal_id)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(goal_id)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(goal_status)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(goal_status)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(goal_description)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(goal_description)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(goal_duration)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(goal_duration)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(goal_set_date)%%>', '1', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(goal_set_date)%%>', urlencode('1'), $templateCode);
		$templateCode = str_replace('<%%VALUE(supervisor_name)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(supervisor_name)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(assigned_to)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(assigned_to)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(goal_setting_str)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(goal_setting_str)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(created_by)%%>', '<%%creatorUsername%%>', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(created_by)%%>', urlencode('<%%creatorUsername%%>'), $templateCode);
		$templateCode = str_replace('<%%VALUE(last_updated_by)%%>', '<%%editorUsername%%>', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(last_updated_by)%%>', urlencode('<%%editorUsername%%>'), $templateCode);
		$templateCode = str_replace('<%%VALUE(created_by_username)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(created_by_username)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(created_at)%%>', '<%%creationDateTime%%>', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(created_at)%%>', urlencode('<%%creationDateTime%%>'), $templateCode);
		$templateCode = str_replace('<%%VALUE(last_updated_by_username)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(last_updated_by_username)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(last_updated_at)%%>', '<%%editingDateTime%%>', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(last_updated_at)%%>', urlencode('<%%editingDateTime%%>'), $templateCode);
	}

	// process translations
	$templateCode = parseTemplate($templateCode);

	// clear scrap
	$templateCode = str_replace('<%%', '<!-- ', $templateCode);
	$templateCode = str_replace('%%>', ' -->', $templateCode);

	// hide links to inaccessible tables
	if(Request::val('dvprint_x') == '') {
		$templateCode .= "\n\n<script>\$j(function() {\n";
		$arrTables = getTableList();
		foreach($arrTables as $name => $caption) {
			$templateCode .= "\t\$j('#{$name}_link').removeClass('hidden');\n";
			$templateCode .= "\t\$j('#xs_{$name}_link').removeClass('hidden');\n";
		}

		$templateCode .= $jsReadOnly;
		$templateCode .= $jsEditable;

		if(!$hasSelectedId) {
		}

		$templateCode.="\n});</script>\n";
	}

	// ajaxed auto-fill fields
	$templateCode .= '<script>';
	$templateCode .= '$j(function() {';


	$templateCode.="});";
	$templateCode.="</script>";
	$templateCode .= $lookups;

	// handle enforced parent values for read-only lookup fields
	$filterField = Request::val('FilterField');
	$filterOperator = Request::val('FilterOperator');
	$filterValue = Request::val('FilterValue');

	// don't include blank images in lightbox gallery
	$templateCode = preg_replace('/blank.gif" data-lightbox=".*?"/', 'blank.gif"', $templateCode);

	// don't display empty email links
	$templateCode=preg_replace('/<a .*?href="mailto:".*?<\/a>/', '', $templateCode);

	/* default field values */
	$rdata = $jdata = get_defaults('goal_setting_table');
	if($hasSelectedId) {
		$jdata = get_joined_record('goal_setting_table', $selectedId);
		if($jdata === false) $jdata = get_defaults('goal_setting_table');
		$rdata = $row;
	}
	$templateCode .= loadView('goal_setting_table-ajax-cache', ['rdata' => $rdata, 'jdata' => $jdata]);

	// hook: goal_setting_table_dv
	if(function_exists('goal_setting_table_dv')) {
		$args = [];
		goal_setting_table_dv(($hasSelectedId ? $selectedId : FALSE), getMemberInfo(), $templateCode, $args);
	}

	return $templateCode;
}